import updateFilesCaches from "~/redux/functions/updateFilesCaches";
import { useCustomAlert } from "~/components/alert/Alert";
import { useAppDispatch } from "~/redux/hooks";
import { __, sprintf } from "@wordpress/i18n";
import { useParams } from "react-router-dom";
import { File } from "~/types/file";
import useFile from "./useFile";
import {
    useRestoreFileMutation,
    /* <fs_premium_only> */
    useToggleFavoriteMutation,
    useTrashFileMutation,
    useDuplicateMediaMutation,
    /* </fs_premium_only> */
} from "~/redux/api/media";
import {
    /* <fs_premium_only> */
    updateFile,
    /* </fs_premium_only> */
    deleteFile as deleteFileAction,
} from "~/redux/features/file/file";
/* <fs_premium_only> */
import {
    useApplyWatermarkMutation,
    useRestoreOriginalsMutation,
} from "~/redux/api/watermark__premium_only";
/* </fs_premium_only> */

const useFileActions = () => {
    const {
        setFile,
        count,
        /* <fs_premium_only> */
        detailsFile,
        /* </fs_premium_only> */
        bulkSelect,
    } = useFile();
    const [restoreFileMutation] = useRestoreFileMutation();
    /* <fs_premium_only> */
    const [applyWatermarkMutation] = useApplyWatermarkMutation();
    const [restoreOriginalsMutation] = useRestoreOriginalsMutation();
    const [trashFileMutation] = useTrashFileMutation();
    const [toggleFavoriteMutation] = useToggleFavoriteMutation();
    const [duplicateMediaMutation] = useDuplicateMediaMutation();
    /* </fs_premium_only> */

    const { dynamicKey } = useParams();

    const dispatch = useAppDispatch();
    const { showAlert } = useCustomAlert();

    const resetState = () => {
        if (bulkSelect) {
            setFile("selectedFiles", []);
            setFile("bulkSelect", false);
        }
    };

    const getFileLink = (file: File) => {
        const url = file?.url;
        if (!url) return;
        navigator.clipboard.writeText(url);

        showAlert({
            toast: true,
            type: "success",
            text: __("File URL copied to clipboard", "ninja-media"),
            timer: 3000,
            timerProgressBar: true,
            showConfirmButton: false,
        });
    };

    const restoreFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: __("Confirm Restore", "ninja-media"),
            text:
                ids.length > 1
                    ? __(
                          "Are you sure you want to restore these files from trash?",
                          "ninja-media",
                      )
                    : __(
                          "Are you sure you want to restore this file from trash?",
                          "ninja-media",
                      ),
            showCancelButton: true,
            confirmButtonText: __("Restore", "ninja-media"),
            onConfirm: async () => {
                try {
                    const response = await restoreFileMutation({
                        ids,
                    }).unwrap();

                    if (bulkSelect) {
                        resetState();
                    }

                    const {
                        restored,
                        allFiles,
                        uncategorized,
                        dynamicFolders,
                        unused,
                        trash,
                    } = response?.data || {};

                    dispatch(deleteFileAction(restored ?? []));

                    const dynamicCount =
                        dynamicKey && dynamicFolders
                            ? dynamicFolders[dynamicKey] ?? 0
                            : Object.keys(dynamicFolders ?? {}).length;

                    setFile("count", {
                        ...count,
                        all: allFiles ?? 0,
                        uncategorized: uncategorized ?? 0,
                        dynamic: dynamicCount,
                        unused: unused ?? 0,
                        trash: trash ?? 0,
                    });

                    updateFilesCaches(restored ?? [], {
                        allFiles,
                        uncategorized,
                        unused,
                        trash,
                        dynamicFolders,
                    });

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            sprintf(
                                __(
                                    "%d file(s) restored successfully",
                                    "ninja-media",
                                ),
                                ids.length,
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to restore files", "ninja-media"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    /* <fs_premium_only> */
    const fileDownload = (attachment: any) => {
        const url = attachment?.url;
        if (!url) return;

        const link = document.createElement("a");
        link.href = url;
        link.download = "";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const applyWatermark = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: __("Apply Watermark", "ninja-media"),
            text:
                ids.length > 1
                    ? __(
                          "Are you sure you want to apply watermark to these files?",
                          "ninja-media",
                      )
                    : __(
                          "Are you sure you want to apply watermark to this file?",
                          "ninja-media",
                      ),
            showCancelButton: true,
            confirmButtonText: __("Apply", "ninja-media"),
            onConfirm: async () => {
                try {
                    const response = await applyWatermarkMutation({
                        ids: ids as number[],
                    }).unwrap();

                    if (bulkSelect) {
                        resetState();
                    }

                    const v = Date.now();

                    response?.data?.files?.forEach((file) => {
                        const bustUrl = (u?: string) =>
                            u ? `${u.split("?")[0]}?v=${v}` : u;

                        dispatch(
                            updateFile({
                                id: file?.id,
                                data: {
                                    url: bustUrl(file?.url),
                                    thumbnailUrl: bustUrl(file?.thumbnailUrl),
                                    updatedAt: file?.updatedAt,
                                    isWatermarked: true,
                                },
                            }),
                        );

                        if (detailsFile?.id === file?.id) {
                            setFile("detailsFile", {
                                ...detailsFile,
                                url: bustUrl(file?.url) as string,
                                thumbnailUrl: bustUrl(file?.thumbnailUrl),
                                updatedAt: file?.updatedAt,
                                isWatermarked: true,
                            });
                        }
                    });

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            sprintf(
                                __(
                                    "%d file(s) watermark applied successfully",
                                    "ninja-media",
                                ),
                                ids.length,
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to apply watermark", "ninja-media"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const removeWatermark = async (ids: (string | number)[]) => {
        showAlert({
            type: "error",
            title: __("Remove Watermark", "ninja-media"),
            text:
                ids.length > 1
                    ? __(
                          "Are you sure you want to remove watermark from these files?",
                          "ninja-media",
                      )
                    : __(
                          "Are you sure you want to remove watermark from this file?",
                          "ninja-media",
                      ),
            showCancelButton: true,
            confirmButtonText: __("Remove", "ninja-media"),
            onConfirm: async () => {
                try {
                    const response = await restoreOriginalsMutation({
                        ids: ids as number[],
                    }).unwrap();

                    if (bulkSelect) {
                        resetState();
                    }

                    const v = Date.now();

                    response?.data?.files?.forEach((file) => {
                        const bustUrl = (u?: string) =>
                            u ? `${u.split("?")[0]}?v=${v}` : u;

                        dispatch(
                            updateFile({
                                id: file?.id,
                                data: {
                                    url: bustUrl(file?.url),
                                    thumbnailUrl: bustUrl(file?.thumbnailUrl),
                                    updatedAt: file?.updatedAt,
                                    isWatermarked: false,
                                },
                            }),
                        );

                        if (detailsFile?.id === file?.id) {
                            setFile("detailsFile", {
                                ...detailsFile,
                                url: bustUrl(file?.url) as string,
                                thumbnailUrl: bustUrl(file?.thumbnailUrl) as string,
                                updatedAt: file?.updatedAt,
                                isWatermarked: false,
                            });
                        }
                    });

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            sprintf(
                                __(
                                    "%d file(s) watermark removed successfully",
                                    "ninja-media",
                                ),
                                ids.length,
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to remove watermark", "ninja-media"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const trashFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "error",
            title: __("Confirm Trash", "ninja-media"),
            text:
                ids.length > 1
                    ? __(
                          "Are you sure you want to move these files to trash?",
                          "ninja-media",
                      )
                    : __(
                          "Are you sure you want to move this file to trash?",
                          "ninja-media",
                      ),
            showCancelButton: true,
            confirmButtonText: __("Trash", "ninja-media"),
            onConfirm: async () => {
                try {
                    const response = await trashFileMutation({ ids }).unwrap();

                    if (bulkSelect) {
                        resetState();
                    }

                    const {
                        trashed,
                        allFiles,
                        uncategorized,
                        dynamicFolders,
                        unused,
                        trash,
                    } = response?.data || {};

                    dispatch(deleteFileAction(trashed ?? []));

                    const dynamicCount =
                        dynamicKey && dynamicFolders
                            ? dynamicFolders[dynamicKey] ?? 0
                            : Object.keys(dynamicFolders ?? {}).length;

                    setFile("count", {
                        ...count,
                        all: allFiles ?? 0,
                        uncategorized: uncategorized ?? 0,
                        dynamic: dynamicCount,
                        unused: unused ?? 0,
                        trash: trash ?? 0,
                    });

                    updateFilesCaches(trashed ?? [], {
                        allFiles,
                        uncategorized,
                        unused,
                        trash,
                        dynamicFolders,
                    });

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            sprintf(
                                __(
                                    "%d file(s) moved to trash successfully",
                                    "ninja-media",
                                ),
                                ids.length,
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to trash files", "ninja-media"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    const toggleFavorite = async (
        ids: (string | number)[],
        favorite: boolean,
    ) => {
        try {
            const response = await toggleFavoriteMutation({
                ids,
                favorite,
            }).unwrap();

            setFile("count", {
                ...count,
                favorites: response?.data?.favorites ?? 0,
            });

            ids.forEach((id) => {
                dispatch(
                    updateFile({
                        id,
                        data: { isFavorite: favorite },
                    }),
                );

                if (detailsFile?.id === id) {
                    setFile("detailsFile", {
                        ...detailsFile,
                        isFavorite: favorite,
                    });
                }
            });

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    (favorite
                        ? `${
                              ids.length > 1 ? `${ids.length} files` : "1 file"
                          } added to favorites`
                        : `${
                              ids.length > 1 ? `${ids.length} files` : "1 file"
                          } removed from favorites`),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text: error?.data?.message || "Failed to update favorites",
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const duplicateFile = async (ids: (string | number)[]) => {
        showAlert({
            type: "info",
            title: "Confirm Duplicate",
            text: `Are you sure you want to duplicate ${
                ids.length > 1 ? "these files" : "this file"
            }?`,
            showCancelButton: true,
            confirmButtonText: "Duplicate",
            onConfirm: async () => {
                try {
                    const response = await duplicateMediaMutation({
                        ids,
                    }).unwrap();

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            `${ids.length} file(s) duplicated successfully`,
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message || "Failed to duplicate files",
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };
    /* </fs_premium_only> */

    return {
        getFileLink,
        restoreFile,
        /* <fs_premium_only> */
        fileDownload,
        applyWatermark,
        removeWatermark,
        trashFile,
        toggleFavorite,
        duplicateFile,
        /* </fs_premium_only> */
    };
};

export default useFileActions;
