import { ServerResponse } from "~/types/response";
import { File } from "~/types/file";
import { baseApi } from "./base";

export interface WatermarkApplyResult {
    id: number;
    success: boolean;
    reason?: string;
}

export interface WatermarkApplyResponse {
    files: File[];
    results: WatermarkApplyResult[];
    message: string;
}

export interface WatermarkBatchResponse {
    results: WatermarkApplyResult[];
    processed: number;
    successCount: number;
}

export interface WatermarkCountResponse {
    count: number;
}

export interface WatermarkEligibleIdsResponse {
    ids: number[];
}

export interface WatermarkRestoreResponse {
    files: File[];
    results: WatermarkApplyResult[];
    message: string;
}

export interface WatermarkBuiltinFont {
    name: string;
    value: string;
}

export interface WatermarkCustomFont {
    slug: string;
    name: string;
    file: string;
}

export interface WatermarkFontsResponse {
    builtin: WatermarkBuiltinFont[];
    custom: WatermarkCustomFont[];
}

export interface WatermarkFontUploadResponse {
    font: WatermarkCustomFont;
    message: string;
}

export interface WatermarkFontDeleteResponse {
    slug: string;
    message: string;
}

export const watermarkApi = baseApi.injectEndpoints({
    endpoints: (builder) => ({
        applyWatermark: builder.mutation<
            ServerResponse<WatermarkApplyResponse>,
            { ids?: number[] }
        >({
            query: (body) => ({
                url: "watermark/apply",
                method: "POST",
                body,
            }),
        }),

        applyWatermarkBatch: builder.mutation<
            ServerResponse<WatermarkBatchResponse>,
            { ids: number[] }
        >({
            query: (body) => ({
                url: "watermark/apply-batch",
                method: "POST",
                body,
            }),
        }),

        getWatermarkCount: builder.query<
            ServerResponse<WatermarkCountResponse>,
            void
        >({
            query: () => ({
                url: "watermark/count",
                method: "GET",
            }),
        }),

        getEligibleIds: builder.query<
            ServerResponse<WatermarkEligibleIdsResponse>,
            void
        >({
            query: () => ({
                url: "watermark/eligible-ids",
                method: "GET",
            }),
        }),

        restoreOriginals: builder.mutation<
            ServerResponse<WatermarkRestoreResponse>,
            { ids: number[] }
        >({
            query: (body) => ({
                url: "watermark/restore",
                method: "POST",
                body,
            }),
        }),

        getWatermarkFonts: builder.query<
            ServerResponse<WatermarkFontsResponse>,
            void
        >({
            query: () => ({ url: "watermark/fonts", method: "GET" }),
            providesTags: ["WatermarkFonts"],
        }),

        uploadWatermarkFont: builder.mutation<
            ServerResponse<WatermarkFontUploadResponse>,
            FormData
        >({
            query: (formData) => ({
                url: "watermark/fonts/upload",
                method: "POST",
                body: formData,
                formData: true,
            }),
            invalidatesTags: ["WatermarkFonts"],
        }),

        deleteWatermarkFont: builder.mutation<
            ServerResponse<WatermarkFontDeleteResponse>,
            { slug: string }
        >({
            query: ({ slug }) => ({
                url: "watermark/fonts",
                method: "DELETE",
                body: { slug },
            }),
            invalidatesTags: ["WatermarkFonts"],
        }),
    }),
});

export const {
    useApplyWatermarkMutation,
    useApplyWatermarkBatchMutation,
    useGetWatermarkCountQuery,
    useLazyGetEligibleIdsQuery,
    useRestoreOriginalsMutation,
    useGetWatermarkFontsQuery,
    useUploadWatermarkFontMutation,
    useDeleteWatermarkFontMutation,
} = watermarkApi;
