import { useReplaceMediaMutation } from "~/redux/api/media";
import { useCustomAlert } from "~/components/alert/Alert";
import { useState } from "@wordpress/element";

export type ReplaceSuccessPayload = {
    id: number;
    url: string;
    thumbnailUrl: string;
};

export const useReplaceMedia = (
    onSuccess?: (payload: ReplaceSuccessPayload) => void,
) => {
    const [loading, setLoading] = useState(false);
    const [replaceMedia] = useReplaceMediaMutation();
    const { showAlert } = useCustomAlert();

    const replaceAttachment = async (attachmentId: number) => {
        const input = document.createElement("input");
        input.type = "file";
        input.style.display = "none";
        input.accept = "image/*,video/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx";

        document.body.appendChild(input);

        input.addEventListener("change", async () => {
            const file = input.files?.[0];
            input.remove();
            if (!file) return;

            setLoading(true);

            try {
                const formData = new FormData();
                formData.append("file", file);

                const result = await replaceMedia({
                    id: attachmentId,
                    formData,
                }).unwrap();

                const freshData = result?.data;

                refreshAttachmentPreview(attachmentId, freshData);

                if (onSuccess && freshData) {
                    const url =
                        typeof freshData.url === "string" ? freshData.url : "";
                    const sizes = freshData.sizes as
                        | Record<string, { url: string }>
                        | undefined;
                    const thumbnailUrl =
                        sizes?.medium?.url ||
                        sizes?.thumbnail?.url ||
                        url;

                    onSuccess({ id: attachmentId, url, thumbnailUrl });
                }

                showAlert({
                    toast: true,
                    type: "success",
                    text: result?.message || "Media replaced successfully.",
                    timer: 3000,
                    timerProgressBar: true,
                    showConfirmButton: false,
                });
            } catch (error: any) {
                showAlert({
                    toast: true,
                    type: "error",
                    text:
                        error?.data?.message ||
                        "Failed to replace media. Please try again.",
                    timer: 4000,
                    timerProgressBar: true,
                    showConfirmButton: false,
                });
            } finally {
                setLoading(false);
            }
        });

        input.click();
    };

    return { replaceAttachment, loading };
};

export function refreshAttachmentPreview(
    attachmentId: number,
    freshData: Record<string, unknown>,
): void {
    const wpMedia = (window as any).wp?.media;
    if (!wpMedia) return;

    const attachment = wpMedia.attachment(attachmentId);
    if (!attachment) return;

    const newUrl = typeof freshData.url === "string" ? freshData.url : "";

    const patch: Record<string, unknown> = {};

    if (newUrl) {
        patch.url = newUrl;
    }

    if (freshData.sizes && typeof freshData.sizes === "object") {
        patch.sizes = freshData.sizes;
    }

    if (Object.keys(patch).length > 0) {
        attachment.set(patch);
    }

    // Directly update every preview <img> to the new URL so the display
    // is instant regardless of whether Backbone triggers a re-render.
    if (newUrl) {
        document
            .querySelectorAll<HTMLImageElement>(
                ".attachment-details img, .attachment-preview img, " +
                ".attachment-details .attachment-media-view img",
            )
            .forEach((img) => {
                img.src = newUrl;
            });
    }
}
