import { WatermarkPosition } from "~/types/watermark__premium_only/watermark";
import PageContainer from "~/components/pageContainer";
import SettingsField from "~/components/settingsField";
import InlineStack from "~/components/inlineStack";
import BlockStack from "~/components/blockStack";
import useSettings from "~/hooks/useSettings";
import Slider from "~/components/slider";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";
import Card from "~/components/card";

const Adjust = () => {
    const { data, setSettings } = useSettings();

    const { position, size, opacity, edgeMargin } = data?.watermark || {};

    return (
        <PageContainer>
            <InlineStack gap={20} wrap={false} blockAlign="start">
                <SettingsField title={__("Position", "ninja-media")}>
                    <Card
                        padding={10}
                        rounded="md"
                        style={{
                            width: "fit-content",
                            display: "grid",
                            gridTemplateColumns: "repeat(3, 43px)",
                            gridTemplateRows: "repeat(3, 43px)",
                            gap: "10px",
                            padding: "10px",
                        }}
                    >
                        {GRID_POSITIONS?.map((pos, index) => {
                            return (
                                <Card
                                    key={pos ?? index}
                                    padding={5}
                                    background={
                                        position === pos ? "primary" : "white"
                                    }
                                    rounded="md"
                                    flex
                                    align="center"
                                    blockAlign="center"
                                    style={{
                                        width: 43,
                                        height: 43,
                                        cursor: "pointer",
                                    }}
                                    onClick={() =>
                                        setSettings("watermark.position", pos)
                                    }
                                >
                                    <span
                                        style={{
                                            width: 8,
                                            height: 8,
                                            borderRadius: "50%",
                                            backgroundColor:
                                                position === pos
                                                    ? "white"
                                                    : "var(--pnpnm-primary)",
                                        }}
                                    />
                                </Card>
                            );
                        })}
                    </Card>
                </SettingsField>

                <BlockStack gap={20}>
                    <SettingsField title={__("Size", "ninja-media")}>
                        <Input
                            type="number"
                            suffix="%"
                            size="small"
                            value={size ?? ""}
                            onChange={(value) =>
                                setSettings("watermark.size", Number(value))
                            }
                        />
                    </SettingsField>

                    <SettingsField title={__("Opacity", "ninja-media")}>
                        <Slider
                            value={opacity ?? 0}
                            onChange={(value) => {
                                setSettings("watermark.opacity", value);
                            }}
                        />
                    </SettingsField>
                </BlockStack>
            </InlineStack>

            <SettingsField
                fullWidth
                title={__("Edge margin", "ninja-media")}
                description={__(
                    "Set the margin between the watermark and the edges of the image.",
                    "ninja-media",
                )}
                secondaryAction={
                    <Input
                        type="number"
                        suffix="px"
                        size="small"
                        value={edgeMargin ?? ""}
                        onChange={(value) =>
                            setSettings("watermark.edgeMargin", Number(value))
                        }
                        fullWidth={false}
                        className="flex-1"
                    />
                }
            />
        </PageContainer>
    );
};

export default Adjust;

export const GRID_POSITIONS: WatermarkPosition[] = [
    "top-left",
    "top-center",
    "top-right",
    "center-left",
    "center",
    "center-right",
    "bottom-left",
    "bottom-center",
    "bottom-right",
];
