import { useCallback, useRef, useState } from "@wordpress/element";
import PageContainer from "~/components/pageContainer";
import SettingsField from "~/components/settingsField";
import InlineStack from "~/components/inlineStack";
import Description from "~/components/description";
import { __, _n, sprintf } from "@wordpress/i18n";
import BlockStack from "~/components/blockStack";
import useSettings from "~/hooks/useSettings";
import Switcher from "~/components/switcher";
import Button from "~/components/button";
import Text from "~/components/text";
import {
    useApplyWatermarkBatchMutation,
    useLazyGetEligibleIdsQuery,
    useRestoreOriginalsMutation,
} from "~/redux/api/watermark__premium_only";

const BATCH_SIZE = 5;

const Apply = () => {
    const { data, setSettings, saveSettings } = useSettings();
    const [fetchEligibleIds] = useLazyGetEligibleIdsQuery();
    const [applyBatch] = useApplyWatermarkBatchMutation();
    const [restoreOriginals] = useRestoreOriginalsMutation();

    const [bulkState, setBulkState] = useState<{
        running: boolean;
        total: number;
        processed: number;
        success: number;
        done: boolean;
    }>({ running: false, total: 0, processed: 0, success: 0, done: false });

    const [restoreState, setRestoreState] = useState<{
        running: boolean;
        done: boolean;
        count: number;
    }>({ running: false, done: false, count: 0 });

    const cancelRef = useRef(false);

    const { type, image, text, backup, applyOnUpload } = data?.watermark || {};

    const startBulkApply = useCallback(async () => {
        if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

        if (bulkState.running) return;
        cancelRef.current = false;

        setBulkState({
            running: true,
            total: 0,
            processed: 0,
            success: 0,
            done: false,
        });

        try {
            if (data) await saveSettings(data);

            const { data: eligibleData } = await fetchEligibleIds();
            const allIds = eligibleData?.data?.ids ?? [];

            if (allIds.length === 0) {
                setBulkState((s) => ({
                    ...s,
                    running: false,
                    done: true,
                }));
                return;
            }

            setBulkState((s) => ({ ...s, total: allIds.length }));

            let processed = 0;
            let success = 0;

            for (let i = 0; i < allIds.length; i += BATCH_SIZE) {
                if (cancelRef.current) break;

                const chunk = allIds.slice(i, i + BATCH_SIZE);
                const res = await applyBatch({ ids: chunk }).unwrap();

                processed += res?.data?.processed ?? chunk.length;
                success += res?.data?.successCount ?? 0;

                setBulkState((s) => ({
                    ...s,
                    processed,
                    success,
                }));
            }

            setBulkState((s) => ({
                ...s,
                running: false,
                done: true,
            }));
        } catch {
            setBulkState((s) => ({
                ...s,
                running: false,
                done: true,
            }));
        }
    }, [data, bulkState.running, saveSettings, fetchEligibleIds, applyBatch]);

    const cancelBulk = () => {
        cancelRef.current = true;
        setBulkState((s) => ({ ...s, running: false, done: true }));
    };

    const startBulkRestore = useCallback(async () => {
        if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

        if (restoreState.running) return;
        setRestoreState({ running: true, done: false, count: 0 });

        try {
            const { data: eligibleData } = await fetchEligibleIds();
            const allIds = eligibleData?.data?.ids ?? [];

            if (allIds.length === 0) {
                setRestoreState({ running: false, done: true, count: 0 });
                return;
            }

            let restoredCount = 0;
            for (let i = 0; i < allIds.length; i += BATCH_SIZE) {
                const chunk = allIds.slice(i, i + BATCH_SIZE);
                const res = await restoreOriginals({ ids: chunk }).unwrap();
                restoredCount +=
                    res?.data?.results.filter((r) => r.success).length ?? 0;
            }

            setRestoreState({
                running: false,
                done: true,
                count: restoredCount,
            });
        } catch {
            setRestoreState({ running: false, done: true, count: 0 });
        }
    }, [restoreState.running, fetchEligibleIds, restoreOriginals]);

    const progress =
        bulkState.total > 0
            ? Math.round((bulkState.processed / bulkState.total) * 100)
            : 0;

    const hasWatermarkSource =
        type === "image" ? !!image : !!text?.content?.trim();

    return (
        <PageContainer>
            <SettingsField
                description={__(
                    "Automatically apply the watermark to new images as they are uploaded to the media library.",
                    "ninja-media",
                )}
                action={
                    <Switcher
                        id="watermarkApplyOnUpload"
                        title={__("Apply Watermark on Upload", "ninja-media")}
                        checked={applyOnUpload ?? false}
                        onChange={() =>
                            setSettings(
                                "watermark.applyOnUpload",
                                !applyOnUpload,
                            )
                        }
                    />
                }
            />

            <SettingsField
                description={__(
                    "Enable this option to keep a backup of the original image before applying the watermark.",
                    "ninja-media",
                )}
                action={
                    <Switcher
                        id="watermarkBackup"
                        title={__("Keep Original Backup", "ninja-media")}
                        checked={backup}
                        onChange={() =>
                            setSettings("watermark.backup", !backup)
                        }
                    />
                }
            >
                <SettingsField.SubField
                    depend={!backup}
                    dependOn="watermarkBackup"
                    title={__("Restore Original", "ninja-media")}
                    description={__(
                        "Restore the original image from the backup. This will remove the watermark from the image.",
                        "ninja-media",
                    )}
                    secondaryAction={
                        <InlineStack gap={10} wrap={false}>
                            <Button
                                variant="primary"
                                size="small"
                                startIcon="restore"
                                onClick={startBulkRestore}
                                loading={restoreState.running}
                            >
                                {restoreState.running
                                    ? __("Restoring…", "ninja-media")
                                    : __("Restore", "ninja-media")}
                            </Button>

                            {restoreState.done && (
                                <Text color="descgray" size="sm">
                                    {sprintf(
                                        _n(
                                            "Restored %d image.",
                                            "Restored %d images.",
                                            restoreState.count,
                                            "ninja-media",
                                        ),
                                        restoreState.count,
                                    )}
                                </Text>
                            )}
                        </InlineStack>
                    }
                />
            </SettingsField>

            <SettingsField
                gap={10}
                title={__("Apply Watermark to Existing Media", "ninja-media")}
            >
                <InlineStack gap={10} wrap={false}>
                    <Button
                        variant="warning"
                        startIcon={bulkState.running ? "sync" : "play_arrow"}
                        className="flex-1"
                        onClick={startBulkApply}
                        loading={bulkState.running}
                        disabled={!hasWatermarkSource}
                    >
                        {bulkState.running
                            ? sprintf(
                                  __("Applying… %d%%", "ninja-media"),
                                  progress,
                              )
                            : __("Apply Watermark", "ninja-media")}
                    </Button>

                    {bulkState.running && (
                        <Button
                            variant="outlined"
                            startIcon="stop_circle"
                            onClick={cancelBulk}
                        >
                            {__("Cancel", "ninja-media")}
                        </Button>
                    )}
                </InlineStack>

                {(bulkState.running || bulkState.done) && (
                    <BlockStack gap={5}>
                        <div
                            style={{
                                width: "100%",
                                height: 8,
                                background: "#e5e7eb",
                                borderRadius: 4,
                                overflow: "hidden",
                            }}
                        >
                            <div
                                style={{
                                    width: `${progress}%`,
                                    height: "100%",
                                    background: "var(--pnpnm-primary, #2271b1)",
                                    borderRadius: 4,
                                    transition: "width 0.3s ease",
                                }}
                            />
                        </div>

                        <Text color="descgray" size="sm">
                            {sprintf(
                                __("%1$d / %2$d processed", "ninja-media"),
                                bulkState.processed,
                                bulkState.total,
                            )}
                            {bulkState.done
                                ? ` — ${sprintf(
                                      __("%d succeeded", "ninja-media"),
                                      bulkState.success,
                                  )}`
                                : ""}
                        </Text>
                    </BlockStack>
                )}

                {!hasWatermarkSource && (
                    <Description
                        text={
                            type === "image"
                                ? __(
                                      "Please select a watermark image first.",
                                      "ninja-media",
                                  )
                                : __(
                                      "Please enter watermark text first.",
                                      "ninja-media",
                                  )
                        }
                    />
                )}

                <Description
                    text={__(
                        "This will apply the watermark to all existing media items in the library that match the specified conditions. This action cannot be undone, so it's recommended to keep a backup of your original images.",
                        "ninja-media",
                    )}
                />
            </SettingsField>
        </PageContainer>
    );
};

export default Apply;
