import SettingsField from "~/components/settingsField";
import InlineStack from "~/components/inlineStack";
import BlockStack from "~/components/blockStack";
import SelectBox from "~/components/selectBox";
import useSettings from "~/hooks/useSettings";
import Switcher from "~/components/switcher";
import Disabled from "~/components/disabled";
import Input from "~/components/input";
import Text from "~/components/text";
import { __ } from "@wordpress/i18n";

const Condition = () => {
    const { data, setSettings } = useSettings();

    const { enabled, minWidth, minHeight, minFileSize, skipRoles, postTypes } =
        data?.watermark?.conditions || {};

    return (
        <SettingsField
            description={__(
                "Enable conditional rules to apply the watermark based on specific criteria.",
                "ninja-media",
            )}
            action={
                <Switcher
                    id="watermarkCondition"
                    title={__("Conditional Rules", "ninja-media")}
                    checked={enabled}
                    onChange={() =>
                        setSettings("watermark.conditions.enabled", !enabled)
                    }
                />
            }
        >
            <Disabled depend={!enabled} dependOn="watermarkCondition">
                <InlineStack gap={10} wrap={false}>
                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Min image width", "ninja-media")}
                        </Text>

                        <Input
                            type="number"
                            size="small"
                            suffix="px"
                            value={minWidth ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.conditions.minWidth",
                                    Number(value),
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Min image height", "ninja-media")}
                        </Text>

                        <Input
                            type="number"
                            size="small"
                            suffix="px"
                            value={minHeight ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.conditions.minHeight",
                                    Number(value),
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Min file size", "ninja-media")}
                        </Text>

                        <Input
                            type="number"
                            size="small"
                            suffix="KB"
                            value={minFileSize ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.conditions.minFileSize",
                                    Number(value),
                                )
                            }
                        />
                    </BlockStack>
                </InlineStack>

                <InlineStack gap={10} wrap={false} blockAlign="start">
                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Skip for user roles", "ninja-media")}
                        </Text>

                        <SelectBox
                            multiple
                            size="small"
                            options={ROLE_OPTIONS}
                            value={skipRoles}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.conditions.skipRoles",
                                    value,
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Post types", "ninja-media")}
                        </Text>

                        <SelectBox
                            multiple
                            size="small"
                            options={POST_TYPE_OPTIONS}
                            value={postTypes}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.conditions.postTypes",
                                    value,
                                )
                            }
                        />
                    </BlockStack>
                </InlineStack>
            </Disabled>
        </SettingsField>
    );
};

export default Condition;

export const ROLE_OPTIONS: {
    name: string;
    value: "administrator" | "editor" | "author" | "contributor" | "subscriber";
}[] = [
    { name: __("Administrator", "ninja-media"), value: "administrator" },
    { name: __("Editor", "ninja-media"), value: "editor" },
    { name: __("Author", "ninja-media"), value: "author" },
    { name: __("Contributor", "ninja-media"), value: "contributor" },
    { name: __("Subscriber", "ninja-media"), value: "subscriber" },
];

export const POST_TYPE_OPTIONS: {
    name: string;
    value: "page" | "post" | "product" | "attachment";
}[] = [
    { name: __("Page", "ninja-media"), value: "page" },
    { name: __("Post", "ninja-media"), value: "post" },
    { name: __("Product (WooCommerce)", "ninja-media"), value: "product" },
    { name: __("Attachment", "ninja-media"), value: "attachment" },
];
