import { useViewDetails } from "../components/FileDetails";
import { useCustomAlert } from "~/components/alert/Alert";
import { useDeleteFile } from "../components/Delete";
import { FileContextMenu } from "~/types/file/file";
import useFileActions from "./useFileActions";
import { __ } from "@wordpress/i18n";
import { File } from "~/types/file";
import useFile from "./useFile";
import { useAppDispatch } from "~/redux/hooks";
import { updateFile } from "~/redux/features/file/file";

declare const wp: any;
/* <fs_premium_only> */
import { useReplaceMedia } from "~/shared/hooks/useReplaceMedia__premium_only";
/* </fs_premium_only> */

type HandleFileContextParams = {
    key: FileContextMenu;
    files: File[];
};

const useFileContext = () => {
    const { setFile, detailsFile } = useFile();
    const dispatch = useAppDispatch();

    const {
        getFileLink,
        restoreFile,
        /* <fs_premium_only> */
        fileDownload,
        applyWatermark,
        removeWatermark,
        trashFile,
        toggleFavorite,
        duplicateFile,
        /* </fs_premium_only> */
    } = useFileActions();

    const { openViewDetails } = useViewDetails();
    const { showAlert } = useCustomAlert();

    /* <fs_premium_only> */
    const { replaceAttachment } = useReplaceMedia(({ id, url, thumbnailUrl }) => {
        dispatch(updateFile({ id, data: { url, thumbnailUrl } }));

        if (detailsFile && String(detailsFile.id) === String(id)) {
            setFile("detailsFile", { ...detailsFile, url, thumbnailUrl });
        }
    });
    /* </fs_premium_only> */

    const { openDeleteFile } = useDeleteFile();

    const handleFileContext = ({ key, files }: HandleFileContextParams) => {
        const ids = files?.map((f) => f?.id) ?? [];

        switch (key) {
            case "open":
                window.open(
                    `${pnpnm?.siteUrl}/wp-admin/upload.php?item=${ids[0]}`,
                    "_blank",
                );
                return;
            case "view":
                setFile("detailsFile", files[0]);
                openViewDetails();
                return;
            case "get":
                getFileLink(files[0]);
                return;
            case "edit":
                window.open(
                    `${pnpnm?.siteUrl}/wp-admin/post.php?post=${ids[0]}&action=edit&open_pnpnm_editor=${ids[0]}`,
                    "_blank",
                );
                return;
            case "download":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                fileDownload(ids?.[0]);
                /* </fs_premium_only> */
                return;
            case "duplicate":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                duplicateFile(ids);
                /* </fs_premium_only> */
                return;
            case "replace":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                replaceAttachment(Number(ids?.[0]));
                /* </fs_premium_only> */
                return;
            case "favorite":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                toggleFavorite(ids, true);
                /* </fs_premium_only> */
                return;
            case "unfavorite":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                toggleFavorite(ids, false);
                /* </fs_premium_only> */
                return;
            case "apply":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                applyWatermark(ids);
                /* </fs_premium_only> */
                return;
            case "remove":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                removeWatermark(ids);
                /* </fs_premium_only> */
                return;
            case "trash":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                trashFile(ids);
                /* </fs_premium_only> */
                return;
            case "restore":
                restoreFile(ids);
                return;
            case "delete":
                openDeleteFile(ids);
                return;
            default: {
                const exhaustiveCheck: never = key;
                return exhaustiveCheck;
            }
        }
    };

    return handleFileContext;
};

export default useFileContext;
