import SettingsField from "~/components/settingsField";
import Description from "~/components/description";
import InlineStack from "~/components/inlineStack";
import BlockStack from "~/components/blockStack";
import useSettings from "~/hooks/useSettings";
import Switcher from "~/components/switcher";
import Disabled from "~/components/disabled";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";
import Text from "~/components/text";

const Tile = () => {
    const { data, setSettings } = useSettings();

    const { enabled, spacingX, spacingY, diagonal } =
        data?.watermark?.tile || {};

    return (
        <SettingsField
            description={__(
                "Repeat the watermark across the entire image in a grid pattern.",
                "ninja-media",
            )}
            action={
                <Switcher
                    id="watermarkTileEnabled"
                    title={__("Tiled / Repeating", "ninja-media")}
                    checked={enabled}
                    onChange={() =>
                        setSettings("watermark.tile.enabled", !enabled)
                    }
                />
            }
        >
            <Disabled depend={!enabled} dependOn="watermarkTileEnabled">
                <InlineStack gap={10} wrap={false}>
                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Horizontal spacing", "ninja-media")}
                        </Text>

                        <Input
                            type="number"
                            size="small"
                            suffix="px"
                            value={spacingX ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.tile.spacingX",
                                    Math.max(0, Number(value)),
                                )
                            }
                        />
                    </BlockStack>

                    <BlockStack gap={10} className="flex-1">
                        <Text size="sm" weight="medium">
                            {__("Vertical spacing", "ninja-media")}
                        </Text>

                        <Input
                            type="number"
                            size="small"
                            suffix="px"
                            value={spacingY ?? ""}
                            onChange={(value) =>
                                setSettings(
                                    "watermark.tile.spacingY",
                                    Math.max(0, Number(value)),
                                )
                            }
                        />
                    </BlockStack>
                </InlineStack>

                <BlockStack gap={10}>
                    <Switcher
                        title={__("Diagonal tiling mode", "ninja-media")}
                        titleSize="sm"
                        checked={diagonal}
                        onChange={() =>
                            setSettings("watermark.tile.diagonal", !diagonal)
                        }
                    />

                    <Description
                        text={__(
                            "Enable this option to tile the watermark diagonally across the image.",
                            "ninja-media",
                        )}
                    />
                </BlockStack>
            </Disabled>
        </SettingsField>
    );
};

export default Tile;
