import { useEffect, useState } from "@wordpress/element";
import PageContainer from "~/components/pageContainer";
import SettingsField from "~/components/settingsField";
import InlineStack from "~/components/inlineStack";
import useSettings from "~/hooks/useSettings";
import Button from "~/components/button";
import { __ } from "@wordpress/i18n";
import Card from "~/components/card";
import Text from "~/components/text";

const Image = () => {
    const { data, setSettings } = useSettings();
    const [imageUrl, setImageUrl] = useState<string>("");

    const { image } = data?.watermark || {};

    useEffect(() => {
        if (!image) {
            setImageUrl("");
            return;
        }

        const attachment = window.wp.media.attachment(image);

        attachment.fetch().then(() => {
            setImageUrl(attachment.get("url") || "");
        });
    }, [image]);

    const openMediaPicker = () => {
        if (!pnpnm?.isPro || !data?.watermark?.enabled) return;

        const wpMedia = window.wp?.media;

        if (typeof wpMedia !== "function") return;

        const frame = wpMedia({
            title: __("Select Watermark Image", "ninja-media"),
            multiple: false,
            library: { type: "image" },
            button: { text: __("Use this image", "ninja-media") },
        });

        frame.on("select", () => {
            const attachment = frame.state().get("selection").first().toJSON();

            setSettings("watermark.image", attachment?.id as number);
        });

        frame.open();
    };

    return (
        <PageContainer>
            <SettingsField
                title={__("Image", "ninja-media")}
                description={__(
                    "Choose the image to use as a watermark. PNG with transparency recommended.",
                    "ninja-media",
                )}
            >
                <Card
                    padding={0}
                    background="extralight"
                    flex
                    align="center"
                    blockAlign="center"
                    style={{
                        position: "relative",
                        width: "400px",
                        height: "200px",
                        overflow: "hidden",
                    }}
                >
                    {imageUrl ? (
                        <img
                            src={imageUrl}
                            alt="watermark"
                            style={{
                                width: "100%",
                                height: "100%",
                                objectFit: "contain",
                            }}
                        />
                    ) : (
                        <Text color="descgray" size="sm">
                            {__("No image selected", "ninja-media")}
                        </Text>
                    )}

                    <InlineStack
                        gap={10}
                        wrap={false}
                        style={{
                            position: "absolute",
                            bottom: "20px",
                            left: "20px",
                        }}
                    >
                        {image ? (
                            <>
                                <Button
                                    variant="error"
                                    size="extrasmall"
                                    startIcon="delete"
                                    onClick={() =>
                                        setSettings("watermark.image", 0)
                                    }
                                >
                                    {__("Remove", "ninja-media")}
                                </Button>

                                <Button
                                    variant="primary"
                                    size="extrasmall"
                                    startIcon="swap_horiz"
                                    onClick={openMediaPicker}
                                >
                                    {__("Change", "ninja-media")}
                                </Button>
                            </>
                        ) : (
                            <Button
                                variant="primary"
                                size="extrasmall"
                                startIcon="add_photo_alternate"
                                onClick={openMediaPicker}
                            >
                                {__("Select Image", "ninja-media")}
                            </Button>
                        )}
                    </InlineStack>
                </Card>
            </SettingsField>
        </PageContainer>
    );
};

export default Image;
